Relying only on route parameters or trusting any claim without validation can lead to broken access control (IDOR / insecure claims usage). You must consistently bind authorization to **trusted identity data** (subject/tenant claims) and enforce it in code.

**VULNERABLE CODE**:

```csharp
using System;
using System.Data.SqlClient;
using Microsoft.AspNetCore.Mvc;

namespace MyApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class ProfilesController : ControllerBase
    {
        private const string ConnectionString = "Server=.;Database=AppDb;Trusted_Connection=True;";

        // ANY authenticated user can read ANY profile by guessing the id
        [HttpGet("{userId}")]
        public IActionResult GetProfile(int userId)
        {
            // BUG: No check that userId belongs to the current user or their tenant
            using var conn = new SqlConnection(ConnectionString);
            conn.Open();

            var cmd = new SqlCommand("SELECT Id, Email, FullName FROM UserProfiles WHERE Id = " + userId, conn);
            using var reader = cmd.ExecuteReader();

            if (!reader.Read())
            {
                return NotFound();
            }

            var result = new
            {
                Id = reader.GetInt32(0),
                Email = reader.GetString(1),
                FullName = reader.GetString(2)
            };

            return Ok(result);
        }
    }
}
```

**Attack Payload** (IDOR using URL tampering):
```text
GET /api/profiles/42 HTTP/1.1
Host: app.example.com
Cookie: .AspNetCore.Cookies=valid-user-session
```

If the attacker is logged in as user with ID 5, they can simply change `42` to any other ID and retrieve someone else’s profile.

**Why This Is Dangerous**:
- No authorization decision is made using trusted claims (e.g., `sub`, `userId`, `tenantId`) – only the caller-controlled route parameter.
- Any authenticated user can enumerate resource IDs and access other users’ data.
- Mixed concerns: raw SQL concatenation also opens the door to SQL injection if the type or binding changes later.

**SECURE VERSION**:

```csharp
using System;
using System.Data.SqlClient;
using System.Security.Claims;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;

namespace MyApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    [Authorize] // Require an authenticated identity with claims
    public class ProfilesController : ControllerBase
    {
        private const string ConnectionString = "Server=.;Database=AppDb;Trusted_Connection=True;";
        private readonly ILogger<ProfilesController> _logger;

        public ProfilesController(ILogger<ProfilesController> logger)
        {
            _logger = logger;
        }

        // Current user reads their own profile, bound to claim not to route ID
        [HttpGet("me")] // No userId parameter here
        public IActionResult GetMyProfile()
        {
            // PRIMARY DEFENSE: use trusted claim for user identity
            string? userIdClaim = User.FindFirstValue(ClaimTypes.NameIdentifier);
            if (string.IsNullOrEmpty(userIdClaim) || !int.TryParse(userIdClaim, out int userId))
            {
                _logger.LogWarning("Missing or invalid NameIdentifier claim for user {User}", User.Identity?.Name);
                return Forbid();
            }

            try
            {
                using var conn = new SqlConnection(ConnectionString);
                conn.Open();

                // DEFENSE-IN-DEPTH: parameterized query
                const string sql = "SELECT Id, Email, FullName FROM UserProfiles WHERE Id = @Id";
                using var cmd = new SqlCommand(sql, conn);
                cmd.Parameters.AddWithValue("@Id", userId);

                using var reader = cmd.ExecuteReader();
                if (!reader.Read())
                {
                    _logger.LogInformation("Profile not found for userId {UserId}", userId);
                    return NotFound();
                }

                var result = new
                {
                    Id = reader.GetInt32(0),
                    Email = reader.GetString(1),
                    FullName = reader.GetString(2)
                };

                return Ok(result);
            }
            catch (SqlException ex)
            {
                // ERROR HANDLING: do not leak details
                _logger.LogError(ex, "Database error when fetching profile for userId {UserId}", userIdClaim);
                return StatusCode(500, "An internal error occurred.");
            }
        }

        // Example: admin can fetch arbitrary profile, checked via claims
        [HttpGet("{userId:int}")]
        [Authorize(Policy = "RequireAdmin")]
        public IActionResult GetProfileForAdmin(int userId)
        {
            // Additional server-side check could validate tenant claims, etc.
            // Implementation would mirror the parameterized query above.
            return StatusCode(501, "Admin endpoint not fully implemented in this example.");
        }
    }
}
```

**Key Security Controls**:
- **Claim-bound identity**: Uses `ClaimTypes.NameIdentifier` from the authenticated principal instead of trusting the route parameter, preventing IDOR.
- **Role/Policy-based authorization**: `[Authorize]` and `RequireAdmin` policy ensure only authorized identities can access sensitive endpoints.
- **Defense in depth with secure coding**: Parameterized queries, structured logging, and generic error responses reduce the blast radius of potential issues and avoid data leakage.

In production, you should bind **every authorization decision** to both the authenticated subject and their tenant/role claims, and enforce this consistently at the controller and data-access layers. Combine claims-based policies, scoped queries (tenant filters), structured audit logging, and environment-specific hardening.

**PRODUCTION PATTERN**:

```csharp
using System;
using System.Data.SqlClient;
using System.Security.Claims;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;

namespace MyApp.Controllers
{
    [ApiController]
    [Route("api/tenants/{tenantId}/[controller]")]
    [Authorize] // baseline: must be authenticated
    public class UsersController : ControllerBase
    {
        private readonly string _connectionString;
        private readonly ILogger<UsersController> _logger;
        private readonly IConfiguration _config;

        public UsersController(IConfiguration config, ILogger<UsersController> logger)
        {
            _config = config;
            _logger = logger;
            _connectionString = config.GetConnectionString("DefaultConnection")!;
        }

        // Tenant admin can list users, but ONLY within their own tenant
        [HttpGet]
        [Authorize(Policy = "TenantAdmin")] // policy checks appropriate role claim
        public async Task<IActionResult> GetUsers(string tenantId)
        {
            string? tenantClaim = User.FindFirstValue("tenant_id");
            string? userId = User.FindFirstValue(ClaimTypes.NameIdentifier);

            // LAYER 1: Validate claims vs route
            if (string.IsNullOrEmpty(tenantClaim) || !string.Equals(tenantClaim, tenantId, StringComparison.Ordinal))
            {
                _logger.LogWarning(
                    "Tenant mismatch for user {UserId}: claimTenant={ClaimTenant}, routeTenant={RouteTenant}",
                    userId, tenantClaim, tenantId);

                // Audit unauthorized cross-tenant attempt
                Audit("TenantAccessDenied", tenantId, userId, "Route-tenant does not match claim tenant");
                return Forbid();
            }

            try
            {
                await using var conn = new SqlConnection(_connectionString);
                await conn.OpenAsync();

                // LAYER 2: Enforce tenant in the query itself
                const string sql = @"SELECT Id, Email, Role FROM Users WHERE TenantId = @TenantId";
                await using var cmd = new SqlCommand(sql, conn);
                cmd.Parameters.AddWithValue("@TenantId", tenantId);

                await using var reader = await cmd.ExecuteReaderAsync();

                var users = new System.Collections.Generic.List<object>();
                while (await reader.ReadAsync())
                {
                    users.Add(new
                    {
                        Id = reader.GetInt32(0),
                        Email = reader.GetString(1),
                        Role = reader.GetString(2)
                    });
                }

                Audit("TenantUserListViewed", tenantId, userId, $"Returned {users.Count} users");
                return Ok(users);
            }
            catch (SqlException ex)
            {
                // LAYER 3: Robust error handling + logging
                _logger.LogError(ex, "Database error listing users for tenant {TenantId}", tenantId);
                Audit("DbError", tenantId, userId, "Database error while listing users");

                if (IsProduction())
                {
                    return StatusCode(500, "An internal error occurred.");
                }
                return StatusCode(500, $"Database error: {ex.Message}");
            }
        }

        private bool IsProduction()
        {
            string? env = _config["ASPNETCORE_ENVIRONMENT"];
            return string.Equals(env, "Production", StringComparison.OrdinalIgnoreCase);
        }

        // Centralized audit logging for sensitive actions
        private void Audit(string eventType, string? tenantId, string? userId, string details)
        {
            // Example: send to dedicated audit logger/sink
            _logger.LogInformation(
                "AUDIT {EventType} | tenant={Tenant} | user={User} | ip={IP} | details={Details}",
                eventType,
                tenantId,
                userId,
                HttpContext.Connection.RemoteIpAddress?.ToString(),
                details);
        }
    }
}
```

**Defense in Depth Layers**:
1. **Claims & route binding**: The controller compares `tenant_id` claim with the `{tenantId}` route segment to prevent cross-tenant access.
   ```csharp
   if (!string.Equals(tenantClaim, tenantId, StringComparison.Ordinal))
   {
       return Forbid();
   }
   ```
2. **Data-layer tenant scoping**: The SQL query enforces `TenantId = @TenantId` so even if upper layers fail, cross-tenant data is not returned.
   ```csharp
   const string sql = "SELECT Id, Email, Role FROM Users WHERE TenantId = @TenantId";
   cmd.Parameters.AddWithValue("@TenantId", tenantId);
   ```
3. **Audit logging & environment-aware error handling**: All sensitive actions and failures are logged with tenant/user context, and responses are sanitized in production.
   ```csharp
   if (IsProduction())
   {
       return StatusCode(500, "An internal error occurred.");
   }
   ```

**Additional Protections**:
- **Environment-specific configuration**: In `appsettings.Production.json`, enforce HTTPS redirection, secure cookies, strict CORS, and strong session/token lifetimes.
- **Rate limiting & anomaly detection**: Apply rate limiting middleware on sensitive endpoints and feed audit logs into SIEM to detect brute-force or enumeration attempts.
- **Security headers & hardening**: Use middleware to set `X-Content-Type-Options`, `X-Frame-Options`, `Content-Security-Policy`, and ensure tokens are validated with proper issuer, audience, and lifetime to prevent token replay and claim tampering.

Manually checking roles in controller code can easily lead to missing or inconsistent authorization checks, enabling privilege escalation or unauthorized access.

**VULNERABLE CODE**:

```csharp
using System;
using System.Linq;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;

namespace MyApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class AdminController : ControllerBase
    {
        private readonly ILogger<AdminController> _logger;

        public AdminController(ILogger<AdminController> logger)
        {
            _logger = logger;
        }

        // VULNERABLE: relies on client-provided header for authorization
        [HttpPost("/api/admin/users/{userId}/promote")] 
        public IActionResult PromoteToAdmin(Guid userId)
        {
            // "X-User-Role" is sent by the client and is fully attacker-controlled
            var role = Request.Headers["X-User-Role"].FirstOrDefault();

            if (role == "Admin")
            {
                // Pretend we update the user role in DB here
                _logger.LogInformation("User {UserId} promoted to admin.", userId);
                return Ok(new { message = "User promoted to admin" });
            }

            // Missing proper logging and context
            return Forbid();
        }
    }
}
```

**Attack Payload** (HTTP request):
```text
POST /api/admin/users/6b2f4f7e-9f70-4e59-8f0a-1b4cb6a1b123/promote HTTP/1.1
Host: vulnerable-app.local
X-User-Role: Admin
Content-Length: 0

```

This request can be sent by any authenticated (or even unauthenticated, depending on other config) user. By simply setting `X-User-Role: Admin`, the attacker bypasses authorization and promotes arbitrary accounts.

**Why This Is Dangerous**:
- Trusts client-controlled data (header) for authorization decisions.
- No server-side verification of the authenticated user’s identity or roles.
- No centralized, declarative authorization policy, making it easy to miss checks on other endpoints.

**SECURE VERSION**:

```csharp
using System;
using System.Security.Claims;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;

namespace MyApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    [Authorize] // Require authenticated user globally for this controller
    public class AdminController : ControllerBase
    {
        private readonly ILogger<AdminController> _logger;

        public AdminController(ILogger<AdminController> logger)
        {
            _logger = logger;
        }

        // PRIMARY DEFENSE: Role-based authorization enforced by the framework
        [HttpPost("users/{userId:guid}/promote")]
        [Authorize(Roles = "Admin")] // Only users with Admin role can access
        public IActionResult PromoteToAdmin(Guid userId)
        {
            // DEFENSE IN DEPTH: double-check identity from server-side principal
            var user = HttpContext.User;
            if (!user.Identity?.IsAuthenticated ?? true)
            {
                _logger.LogWarning("Unauthenticated access attempt to PromoteToAdmin.");
                return Unauthorized();
            }

            var callerId = user.FindFirstValue(ClaimTypes.NameIdentifier) ?? "unknown";
            var isAdmin = user.IsInRole("Admin");
            if (!isAdmin)
            {
                _logger.LogWarning(
                    "User {CallerId} tried to promote {TargetUserId} without admin role.",
                    callerId, userId);
                return Forbid();
            }

            try
            {
                // Here you would load the user from DB and change their role.
                // Example: _userService.PromoteToAdmin(userId);

                _logger.LogInformation(
                    "Admin {CallerId} promoted user {TargetUserId} to admin.",
                    callerId, userId);

                return Ok(new { message = "User promoted to admin" });
            }
            catch (Exception ex)
            {
                // FAIL SECURELY: log internal details, return generic message
                _logger.LogError(ex,
                    "Error while admin {CallerId} attempted to promote {TargetUserId}.",
                    callerId, userId);

                return StatusCode(500, new { error = "Internal server error" });
            }
        }
    }
}
```

**Key Security Controls**:
- **Framework-enforced role-based authorization**: Uses `[Authorize(Roles = "Admin")]` so the ASP.NET Core authorization middleware, not client data, decides who can access the endpoint.
- **Server-side identity and role checks**: Reads roles and claims from `HttpContext.User`, which is populated by the authentication middleware from trusted tokens or cookies, not from headers supplied by the client.
- **Secure logging and error handling**: Logs unauthorized attempts with user context, catches exceptions, and returns generic error messages to avoid leaking internals while still providing audit trails.

In production you should centralize authorization into policies, use custom handlers for complex logic (like per-tenant admins), and add strong audit logging, rate limiting, and environment-specific hardening.

**PRODUCTION PATTERN**:

```csharp
using System;
using System.Security.Claims;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;

namespace MyApp.Controllers
{
    // Custom requirement: caller must be TenantAdmin for the target tenant
    public class TenantAdminRequirement : IAuthorizationRequirement { }

    public class TenantAdminHandler : AuthorizationHandler<TenantAdminRequirement>
    {
        private readonly ILogger<TenantAdminHandler> _logger;

        public TenantAdminHandler(ILogger<TenantAdminHandler> logger)
        {
            _logger = logger;
        }

        protected override Task HandleRequirementAsync(
            AuthorizationHandlerContext context,
            TenantAdminRequirement requirement)
        {
            var tenantId = context.User.FindFirst("tenant_id")?.Value;
            var isTenantAdmin = context.User.IsInRole($"TenantAdmin:{tenantId}");

            if (!string.IsNullOrEmpty(tenantId) && isTenantAdmin)
            {
                context.Succeed(requirement);
            }
            else
            {
                _logger.LogWarning(
                    "Tenant admin authorization failed. TenantId={TenantId}, User={UserId}",
                    tenantId,
                    context.User.FindFirstValue(ClaimTypes.NameIdentifier) ?? "unknown");
            }

            return Task.CompletedTask;
        }
    }

    [ApiController]
    [Route("api/[controller]")]
    [Authorize] // Require authentication for all actions
    public class TenantAdminController : ControllerBase
    {
        private readonly ILogger<TenantAdminController> _logger;
        private readonly IConfiguration _config;

        public TenantAdminController(ILogger<TenantAdminController> logger, IConfiguration config)
        {
            _logger = logger;
            _config = config;
        }

        // Policy defined in Program.cs/Startup: options.AddPolicy("TenantAdminPolicy", ...)
        [HttpPost("{tenantId:guid}/users/{userId:guid}/promote")]        
        [Authorize(Policy = "TenantAdminPolicy")]        
        public IActionResult PromoteTenantUser(Guid tenantId, Guid userId)
        {
            var user = HttpContext.User;
            var callerId = user.FindFirstValue(ClaimTypes.NameIdentifier) ?? "unknown";
            var callerTenantId = user.FindFirst("tenant_id")?.Value;

            // DEFENSE IN DEPTH: Ensure route tenant matches caller's tenant claim
            if (!Guid.TryParse(callerTenantId, out var callerTenantGuid) || callerTenantGuid != tenantId)
            {
                _logger.LogWarning(
                    "Cross-tenant access attempt by {CallerId}. CallerTenant={CallerTenant}, TargetTenant={TargetTenant}",
                    callerId, callerTenantId, tenantId);
                return Forbid();
            }

            try
            {
                // RATE LIMITING (conceptual): enforce at middleware or API gateway layer
                // e.g., use AspNetCoreRateLimit or gateway-level rate limiting

                // Perform the privileged action (e.g., update DB)
                // _userService.PromoteUserInTenant(tenantId, userId);

                // AUDIT LOGGING: sensitive action trail
                _logger.LogInformation(
                    "AUDIT: TenantAdmin {CallerId} promoted user {UserId} in tenant {TenantId} at {Timestamp}",
                    callerId, userId, tenantId, DateTime.UtcNow);

                return Ok(new { message = "Tenant user promoted" });
            }
            catch (Exception ex)
            {
                // Centralized error logging
                _logger.LogError(ex,
                    "Error during tenant admin operation by {CallerId} in tenant {TenantId} on user {UserId}",
                    callerId, tenantId, userId);

                // GRACEFUL DEGRADATION: fail closed
                return StatusCode(500, new { error = "Internal server error" });
            }
        }
    }
}
```

**Defense in Depth Layers**:
1. **Policy-based authorization with custom handlers**  
   Encapsulate complex logic (like per-tenant admin rights) inside policies and handlers, not scattered `if` statements:
   ```csharp
   services.AddAuthorization(options =>
   {
       options.AddPolicy("TenantAdminPolicy", policy =>
       {
           policy.RequireAuthenticatedUser();
           policy.AddRequirements(new TenantAdminRequirement());
       });
   });

   services.AddSingleton<IAuthorizationHandler, TenantAdminHandler>();
   ```
2. **Tenant isolation and claim validation**  
   Ensure the tenant in the route matches the tenant claim to prevent horizontal privilege escalation:
   ```csharp
   if (callerTenantGuid != tenantId)
   {
       return Forbid();
   }
   ```
3. **Environment-specific hardening and security headers**  
   Configure production differently from development and add security headers at startup:
   ```csharp
   if (builder.Environment.IsProduction())
   {
       app.UseHsts();
       app.Use(async (context, next) =>
       {
           context.Response.Headers["X-Content-Type-Options"] = "nosniff";
           context.Response.Headers["X-Frame-Options"] = "DENY";
           context.Response.Headers["X-XSS-Protection"] = "0";
           await next();
       });
   }
   ```

**Additional Protections**:
- **Centralized audit logging**: Log every sensitive admin/tenant-admin action with who, what, when, and which tenant, and ship logs to SIEM for alerting.
- **Rate limiting and anomaly detection**: Apply rate limits on admin APIs and alert on unusual patterns (e.g., many role changes in a short time or from new IPs).
- **Zero-trust configuration management**: Never trust client-supplied headers or query parameters for roles/tenants; rely on signed tokens (JWT) or secure cookies, plus short-lived access tokens and regular role/tenant revalidation.

Relying only on user identity or roles without checking ownership of each resource leads to broken access control. You need resource-based authorization that validates the current user against the specific resource being accessed.

**VULNERABLE CODE**:

```csharp
using System;
using System.Collections.Generic;
using Microsoft.AspNetCore.Mvc;

namespace MyApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class DocumentsController : ControllerBase
    {
        // Simulated in-memory store: docId -> ownerUserId
        private static readonly Dictionary<int, string> Documents = new()
        {
            { 1, "alice" },
            { 2, "bob" },
            { 3, "charlie" }
        };

        // VULNERABLE: only checks authentication, not ownership
        [HttpGet("{id:int}")]
        public IActionResult GetDocument(int id)
        {
            if (!User.Identity?.IsAuthenticated ?? true)
            {
                return Unauthorized();
            }

            if (!Documents.ContainsKey(id))
            {
                return NotFound();
            }

            // Any authenticated user can read any document
            var owner = Documents[id];
            return Ok(new { Id = id, Owner = owner, Content = $"Secret for {owner}" });
        }
    }
}
```

**Attack Payload** (HTTP request crafted by a malicious authenticated user):
```bash
# Attacker logged in as "bob" tries to access Alice's document (id=1)
curl -H "Authorization: Bearer <bob_jwt_token>" \
     https://api.example.com/api/documents/1
```

**Why This Is Dangerous**:
- Any authenticated user can access any document by just guessing or iterating IDs.
- There is no resource-level check that `User.Identity.Name` matches the document owner.
- Similar patterns caused real-world leaks (e.g., project export/download endpoints not enforcing per-resource authorization).

**SECURE VERSION**:

```csharp
using System;
using System.Collections.Generic;
using System.Security.Claims;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;

namespace MyApp.Controllers
{
    public record Document(int Id, string OwnerUserId, string Content);

    public interface IDocumentRepository
    {
        Document? GetById(int id);
    }

    public class InMemoryDocumentRepository : IDocumentRepository
    {
        private static readonly Dictionary<int, Document> Documents = new()
        {
            { 1, new Document(1, "alice", "Alice's secret") },
            { 2, new Document(2, "bob", "Bob's secret") },
            { 3, new Document(3, "charlie", "Charlie's secret") }
        };

        public Document? GetById(int id)
        {
            return Documents.TryGetValue(id, out var doc) ? doc : null;
        }
    }

    [ApiController]
    [Route("api/[controller]")]
    public class SecureDocumentsController : ControllerBase
    {
        private readonly IDocumentRepository _repository;
        private readonly ILogger<SecureDocumentsController> _logger;

        public SecureDocumentsController(IDocumentRepository repository,
                                         ILogger<SecureDocumentsController> logger)
        {
            _repository = repository;
            _logger = logger;
        }

        // PRIMARY DEFENSE: Resource-based authorization check
        [HttpGet("{id:int}")]
        [Authorize] // Ensure user is authenticated
        public IActionResult GetDocument(int id)
        {
            if (id <= 0)
            {
                return BadRequest("Invalid id");
            }

            var userId = User.FindFirstValue(ClaimTypes.NameIdentifier) ?? User.Identity?.Name;
            if (string.IsNullOrEmpty(userId))
            {
                _logger.LogWarning("Authorized request without NameIdentifier. User: {User}", User.Identity?.Name);
                return Forbid();
            }

            var doc = _repository.GetById(id);
            if (doc == null)
            {
                return NotFound();
            }

            // Enforce ownership
            if (!string.Equals(doc.OwnerUserId, userId, StringComparison.OrdinalIgnoreCase))
            {
                _logger.LogWarning("Access denied. User {UserId} tried to access document {DocId} owned by {Owner}",
                    userId, doc.Id, doc.OwnerUserId);
                return Forbid(); // Do not leak existence details
            }

            return Ok(new { doc.Id, Content = doc.Content });
        }
    }
}
```

**Key Security Controls**:
- Resource-based authorization: The code explicitly compares the current user's identifier with the resource's owner before returning it.
- Least privilege and fail-closed logic: If the user ID is missing or the owner doesn't match, the request is denied with `Forbid()`.
- Secure logging and input validation: Access denials are logged with minimal detail to support incident investigation without leaking sensitive information.

In production, you should centralize authorization logic with ASP.NET Core's policy-based and resource-based authorization. Define handlers that understand your domain (owner, shared users, admins), and apply them consistently across controllers. Combine this with proper logging, environment-aware configuration, and rate limiting.

**PRODUCTION PATTERN**:

```csharp
using System;
using System.Collections.Generic;
using System.Linq;
using System.Security.Claims;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;

namespace MyApp.Authorization
{
    // DOMAIN MODEL
    public class Document
    {
        public int Id { get; init; }
        public string OwnerUserId { get; init; } = string.Empty;
        public List<string> SharedWithUserIds { get; init; } = new();
        public string Content { get; init; } = string.Empty;
    }

    public interface IDocumentRepository
    {
        Document? GetById(int id);
    }

    // AUTHORIZATION REQUIREMENTS
    public class DocumentAccessRequirement : IAuthorizationRequirement
    {
        public bool AllowAdmins { get; }

        public DocumentAccessRequirement(bool allowAdmins = true)
        {
            AllowAdmins = allowAdmins;
        }
    }

    // RESOURCE-BASED AUTHORIZATION HANDLER
    public class DocumentAccessHandler : AuthorizationHandler<DocumentAccessRequirement, Document>
    {
        private readonly ILogger<DocumentAccessHandler> _logger;

        public DocumentAccessHandler(ILogger<DocumentAccessHandler> logger)
        {
            _logger = logger;
        }

        protected override Task HandleRequirementAsync(
            AuthorizationHandlerContext context,
            DocumentAccessRequirement requirement,
            Document resource)
        {
            var userId = context.User.FindFirstValue(ClaimTypes.NameIdentifier)
                         ?? context.User.Identity?.Name;

            if (string.IsNullOrEmpty(userId))
            {
                _logger.LogWarning("Authorization failed: missing NameIdentifier claim.");
                return Task.CompletedTask;
            }

            // 1. Admins can access (if allowed)
            if (requirement.AllowAdmins && context.User.IsInRole("Admin"))
            {
                _logger.LogInformation("Admin {UserId} accessing document {DocId}", userId, resource.Id);
                context.Succeed(requirement);
                return Task.CompletedTask;
            }

            // 2. Owner can access
            if (string.Equals(resource.OwnerUserId, userId, StringComparison.OrdinalIgnoreCase))
            {
                context.Succeed(requirement);
                return Task.CompletedTask;
            }

            // 3. Shared-with access
            if (resource.SharedWithUserIds.Any(u =>
                    string.Equals(u, userId, StringComparison.OrdinalIgnoreCase)))
            {
                context.Succeed(requirement);
                return Task.CompletedTask;
            }

            _logger.LogWarning("Access denied. User {UserId} is not authorized for document {DocId}", userId, resource.Id);
            return Task.CompletedTask; // Fail closed by default
        }
    }
}

namespace MyApp.Controllers
{
    using MyApp.Authorization;

    [ApiController]
    [Route("api/[controller]")]
    public class DocumentsController : ControllerBase
    {
        private readonly IDocumentRepository _repository;
        private readonly IAuthorizationService _authorizationService;
        private readonly ILogger<DocumentsController> _logger;
        private readonly IConfiguration _config;

        public DocumentsController(
            IDocumentRepository repository,
            IAuthorizationService authorizationService,
            ILogger<DocumentsController> logger,
            IConfiguration config)
        {
            _repository = repository;
            _authorizationService = authorizationService;
            _logger = logger;
            _config = config;
        }

        [HttpGet("{id:int}")]
        [Authorize] // Baseline: must be authenticated
        public async Task<IActionResult> Get(int id)
        {
            if (id <= 0)
            {
                return BadRequest("Invalid id");
            }

            // Environment-specific behavior
            var isProd = string.Equals(_config["ASPNETCORE_ENVIRONMENT"], "Production", StringComparison.OrdinalIgnoreCase);

            // Basic rate limiting stub (replace with real middleware like AspNetCoreRateLimit)
            // Here we just log; in real apps use a middleware or gateway to enforce limits.
            _logger.LogInformation("Document {Id} requested by {User}", id, User.Identity?.Name);

            Document? doc;
            try
            {
                doc = _repository.GetById(id);
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Error loading document {Id}", id);
                return StatusCode(500, isProd ? "Internal server error" : ex.Message);
            }

            if (doc == null)
            {
                return NotFound();
            }

            // Centralized resource-based authorization
            var authResult = await _authorizationService.AuthorizeAsync(
                User, doc, new DocumentAccessRequirement(allowAdmins: true));

            if (!authResult.Succeeded)
            {
                // Audit log
                _logger.LogWarning("Authorization failure for user {User} on document {DocId}",
                    User.Identity?.Name, doc.Id);

                // Avoid leaking whether the user is owner/shared or not
                return Forbid();
            }

            // Example of setting security headers (if using MVC + filters/middleware, centralize this)
            Response.Headers["X-Content-Type-Options"] = "nosniff";
            Response.Headers["X-Frame-Options"] = "DENY";
            Response.Headers["X-XSS-Protection"] = "0"; // Rely on CSP in real apps

            return Ok(new { doc.Id, doc.Content });
        }
    }
}
```

**Defense in Depth Layers**:
1. **Centralized policy & role/ownership checks**:
   - `DocumentAccessRequirement` and `DocumentAccessHandler` encapsulate all logic about who can access a document.
   - Example:
   ```csharp
   var authResult = await _authorizationService.AuthorizeAsync(
       User, doc, new DocumentAccessRequirement(allowAdmins: true));
   ```
   This keeps controllers thin and prevents inconsistent ad-hoc checks.

2. **Least privilege + fail-closed defaults**:
   - If user identity is missing or not owner/admin/shared, the handler does not call `context.Succeed`, so access is denied by default.
   - Example:
   ```csharp
   if (string.IsNullOrEmpty(userId))
   {
       _logger.LogWarning("Authorization failed: missing NameIdentifier claim.");
       return Task.CompletedTask; // No Succeed -> forbidden
   }
   ```

3. **Monitoring, logging, and environment-aware error handling**:
   - Detailed logs for failures and exceptions, but generic error messages in production.
   - Example:
   ```csharp
   catch (Exception ex)
   {
       _logger.LogError(ex, "Error loading document {Id}", id);
       return StatusCode(500, isProd ? "Internal server error" : ex.Message);
   }
   ```

**Additional Protections**:
- Use a real rate limiting solution (e.g., API gateway, `AspNetCoreRateLimit`, or reverse proxy) to throttle repeated access attempts and enumeration.
- Configure strong authentication and claims mapping so `NameIdentifier` is reliable, and regularly review admin role assignments.
- Add comprehensive audit logging (who accessed which document and when) and integrate with SIEM or monitoring tools to detect abnormal access patterns or suspected abuse of admin privileges.

If you only check that a user is authenticated, but not whether they are allowed to access a specific resource, you create a classic broken access control issue.

**VULNERABLE CODE**:

```csharp
using System;
using System.Collections.Generic;
using System.Linq;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;

namespace MyApp.Api.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class OrdersController : ControllerBase
    {
        // Simulated in-memory store
        private static readonly List<Order> Orders = new List<Order>
        {
            new Order { Id = 1, UserId = "user-123", Total = 100.0m },
            new Order { Id = 2, UserId = "user-456", Total = 50.0m },
            new Order { Id = 3, UserId = "user-123", Total = 75.0m }
        };

        // Only checks that the caller is authenticated
        [HttpGet("{orderId}")]
        [Authorize] // ✅ Authenticated, but ❌ no authorization check
        public ActionResult<Order> GetOrder(int orderId)
        {
            // Missing: filter by current user
            var order = Orders.FirstOrDefault(o => o.Id == orderId);
            if (order == null)
            {
                return NotFound();
            }

            // Any logged-in user can access any order by ID
            return Ok(order);
        }
    }

    public class Order
    {
        public int Id { get; set; }
        public string UserId { get; set; } = string.Empty;
        public decimal Total { get; set; }
    }
}
```

**Attack Payload** (HTTP request):
```bash
curl -H "Authorization: Bearer ATTACKER_JWT" \
  https://api.example.com/api/orders/1
```

- If `ATTACKER_JWT` belongs to `user-456`, they can still retrieve order `1` which belongs to `user-123`.

**Why This Is Dangerous**:
- Any authenticated user can enumerate and access other users' orders by changing the `orderId`.
- There is no check that the resource owner (`UserId`) matches the authenticated user.
- Lack of role checks means non-admins could access data intended only for admins.

**SECURE VERSION**:

```csharp
using System;
using System.Collections.Generic;
using System.Linq;
using System.Security.Claims;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;

namespace MyApp.Api.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class OrdersController : ControllerBase
    {
        private static readonly List<Order> Orders = new List<Order>
        {
            new Order { Id = 1, UserId = "user-123", Total = 100.0m },
            new Order { Id = 2, UserId = "user-456", Total = 50.0m },
            new Order { Id = 3, UserId = "user-123", Total = 75.0m }
        };

        private readonly ILogger<OrdersController> _logger;

        public OrdersController(ILogger<OrdersController> logger)
        {
            _logger = logger;
        }

        // User can only access their own orders
        [HttpGet("{orderId:int}")]
        [Authorize] // Require authentication
        public ActionResult<Order> GetOwnOrder(int orderId)
        {
            var userId = User.FindFirstValue(ClaimTypes.NameIdentifier);
            if (string.IsNullOrEmpty(userId))
            {
                _logger.LogWarning("Missing NameIdentifier claim for user");
                return Forbid();
            }

            var order = Orders.FirstOrDefault(o => o.Id == orderId && o.UserId == userId);
            if (order == null)
            {
                // Do not reveal whether the ID exists for another user
                _logger.LogInformation("Order {OrderId} not found or not owned by user {UserId}", orderId, userId);
                return NotFound();
            }

            return Ok(order);
        }

        // Admin-only endpoint to view any order
        [HttpGet("admin/{orderId:int}")]
        [Authorize(Roles = "Admin")] // Role-based authorization
        public ActionResult<Order> GetAnyOrder(int orderId)
        {
            var order = Orders.FirstOrDefault(o => o.Id == orderId);
            if (order == null)
            {
                return NotFound();
            }

            _logger.LogInformation("Admin {AdminId} accessed order {OrderId}",
                User.FindFirstValue(ClaimTypes.NameIdentifier), orderId);

            return Ok(order);
        }
    }

    public class Order
    {
        public int Id { get; set; }
        public string UserId { get; set; } = string.Empty;
        public decimal Total { get; set; }
    }
}
```

**Key Security Controls**:
- **Per-resource authorization check**: The `GetOwnOrder` method filters by both `orderId` and `UserId`, ensuring users can only access their own resources.
- **Role-based access control (RBAC)**: The admin route uses `[Authorize(Roles = "Admin")]` so only admins can access other users' orders.
- **Secure error handling and logging**: Uses `NotFound()` for missing/unauthorized resources (avoiding information leaks) and logs access attempts for auditing and detection.

In production, you want consistent, centrally managed authorization: a policy-based approach, tenant isolation baked into every query, and good observability. ASP.NET Core's policy system plus custom handlers works well for this.

**PRODUCTION PATTERN**:

```csharp
using System;
using System.Collections.Generic;
using System.Linq;
using System.Security.Claims;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;

namespace MyApp.Api.Authorization
{
    // Requirement: caller must own the resource and be in the same tenant
    public class OrderOwnerRequirement : IAuthorizationRequirement { }

    public class OrderOwnerHandler : AuthorizationHandler<OrderOwnerRequirement, Order>
    {
        private readonly ILogger<OrderOwnerHandler> _logger;

        public OrderOwnerHandler(ILogger<OrderOwnerHandler> logger)
        {
            _logger = logger;
        }

        protected override Task HandleRequirementAsync(
            AuthorizationHandlerContext context,
            OrderOwnerRequirement requirement,
            Order resource)
        {
            var userId = context.User.FindFirstValue(ClaimTypes.NameIdentifier);
            var tenantId = context.User.FindFirst("tenant_id")?.Value;

            if (userId == null || tenantId == null)
            {
                _logger.LogWarning("Authorization failed: missing claims");
                return Task.CompletedTask;
            }

            // Defense in depth: enforce tenant and ownership
            if (resource.UserId == userId && resource.TenantId == tenantId)
            {
                context.Succeed(requirement);
            }
            else
            {
                _logger.LogWarning(
                    "Order ownership check failed. User {UserId} Tenant {TenantId} -> Order {OrderId} Owner {OwnerId} Tenant {OrderTenant}",
                    userId, tenantId, resource.Id, resource.UserId, resource.TenantId);
            }

            return Task.CompletedTask;
        }
    }
}

namespace MyApp.Api.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class OrdersController : ControllerBase
    {
        private readonly IOrderRepository _orders;
        private readonly IAuthorizationService _authorizationService;
        private readonly ILogger<OrdersController> _logger;
        private readonly IConfiguration _configuration;

        public OrdersController(
            IOrderRepository orders,
            IAuthorizationService authorizationService,
            ILogger<OrdersController> logger,
            IConfiguration configuration)
        {
            _orders = orders;
            _authorizationService = authorizationService;
            _logger = logger;
            _configuration = configuration;
        }

        [HttpGet("{orderId:int}")]
        [Authorize]
        public async Task<IActionResult> GetOrder(int orderId)
        {
            try
            {
                var order = await _orders.GetByIdAsync(orderId);
                if (order == null)
                {
                    return NotFound();
                }

                var authResult = await _authorizationService.AuthorizeAsync(
                    User, order, new OrderOwnerRequirement());

                if (!authResult.Succeeded)
                {
                    _logger.LogWarning("Access denied to order {OrderId} for user {UserId}",
                        orderId, User.FindFirstValue(ClaimTypes.NameIdentifier));
                    return Forbid();
                }

                _logger.LogInformation("User {UserId} accessed own order {OrderId}",
                    User.FindFirstValue(ClaimTypes.NameIdentifier), orderId);

                return Ok(order);
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Error retrieving order {OrderId}", orderId);
                // Graceful degradation: generic error message
                return StatusCode(500, "An unexpected error occurred.");
            }
        }

        [HttpGet("admin/{orderId:int}")]
        [Authorize(Policy = "AdminOnly")]
