        public IActionResult DoAdminAction([FromBody] AdminRequest request)
        {
            // Client tells us what role they are (BROKEN AUTHZ)
            if (request.Role != "Admin")
            {
                return Forbid();
            }

            // Dangerous admin-only logic
            if (request.Action == "DisableUser")
            {
