**Key Security Controls**:
- **Server-side Role Enforcement**: Uses `[Authorize(Roles = "Admin")]` to ensure only authenticated users with the `Admin` role (from a trusted token or identity store) can access the endpoint.
- **Input Validation & Error Handling**: Validates `TargetUserId`, uses `ModelState`, and handles exceptions with generic error messages while logging detailed info server-side.
- **Audit Logging**: Logs who performed which admin action and when (`AdminId`, `TargetUserId`, `Timestamp`), supporting forensics and anomaly detection.

In production, you usually need fine-grained, policy-based authorization: multiple roles, per-tenant boundaries, and auditable decisions. ASP.NET Core's policy system and custom authorization handlers are a good fit.

**PRODUCTION PATTERN**:

```csharp
using System;
using System.Security.Claims;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;

namespace MyApp.Controllers
{
    // Custom requirement representing "can manage users in this tenant"
    public class ManageTenantUsersRequirement : IAuthorizationRequirement
    {
        public string RequiredRole { get; }

        public ManageTenantUsersRequirement(string requiredRole)
        {
            RequiredRole = requiredRole;
        }
    }

    // Authorization handler: checks role AND tenant match
    public class ManageTenantUsersHandler : AuthorizationHandler<ManageTenantUsersRequirement>
    {
        protected override Task HandleRequirementAsync(
            AuthorizationHandlerContext context,
            ManageTenantUsersRequirement requirement)
        {
            var role = context.User.FindFirstValue(ClaimTypes.Role);
            var tenantId = context.User.FindFirst("tenant_id")?.Value;

            if (string.IsNullOrEmpty(role) || string.IsNullOrEmpty(tenantId))
            {
                return Task.CompletedTask;
            }

            // Example: GlobalAdmin can manage any tenant, TenantAdmin only their own
            if (role == "GlobalAdmin")
            {
                context.Succeed(requirement);
            }
            else if (role == requirement.RequiredRole)
            {
                context.Succeed(requirement);
            }

            return Task.CompletedTask;
        }
    }

    public class TenantAdminRequest
    {
        public string TenantId { get; set; } = string.Empty;
        public string TargetUserId { get; set; } = string.Empty;
        public string Action { get; set; } = string.Empty;
    }

    [ApiController]
    [Route("api/[controller]")]
    public class TenantAdminController : ControllerBase
    {
        private readonly IAuthorizationService _authorizationService;
        private readonly ILogger<TenantAdminController> _logger;
        private readonly IConfiguration _configuration;

        public TenantAdminController(
            IAuthorizationService authorizationService,
            ILogger<TenantAdminController> logger,
            IConfiguration configuration)
        {
            _authorizationService = authorizationService;
            _logger = logger;
            _configuration = configuration;
        }

        [HttpPost("manage-user")]
        [Authorize] // Baseline: must be authenticated
        public async Task<IActionResult> ManageUserAsync([FromBody] TenantAdminRequest request)
        {
            if (!ModelState.IsValid)
            {
                return BadRequest(ModelState);
            }

            // Input validation
            if (string.IsNullOrWhiteSpace(request.TenantId) ||
                string.IsNullOrWhiteSpace(request.TargetUserId))
            {
                return BadRequest("TenantId and TargetUserId are required.");
            }

            var userId = User.FindFirstValue(ClaimTypes.NameIdentifier) ?? "unknown";
            var userTenantId = User.FindFirst("tenant_id")?.Value;

            // Defense: enforce tenant boundary even before policy
            if (!string.Equals(request.TenantId, userTenantId, StringComparison.Ordinal))
            {
                _logger.LogWarning(
                    "Cross-tenant access attempt by {UserId} from {UserTenant} to {TargetTenant}",
                    userId,
                    userTenantId,
                    request.TenantId);

                return Forbid();
            }

            // Policy-based authorization: role + tenant checks in handler
            var requirement = new ManageTenantUsersRequirement("TenantAdmin");
            var authResult = await _authorizationService.AuthorizeAsync(User, null, requirement);

            if (!authResult.Succeeded)
            {
                _logger.LogWarning(
                    "Authorization failed for {UserId} on tenant {TenantId} with action {Action}",
                    userId,
                    request.TenantId,
                    request.Action);
                return Forbid();
            }

            try
            {
                switch (request.Action)
                {
                    case "DisableUser":
                        // TODO: Call domain service/repository with scoped DbContext
                        _logger.LogInformation(
                            "User {TargetUserId} disabled by {AdminId} in tenant {TenantId} at {Timestamp}",
                            request.TargetUserId,
                            userId,
                            request.TenantId,
                            DateTimeOffset.UtcNow);
                        break;

                    case "ResetPassword":
                        _logger.LogInformation(
                            "Password reset for {TargetUserId} by {AdminId} in tenant {TenantId}",
                            request.TargetUserId,
                            userId,
                            request.TenantId);
                        break;

                    default:
                        return BadRequest("Unknown action.");
                }

                // Simple rate limiting concept via config (real-world: use middleware / gateway)
                var env = _configuration["ASPNETCORE_ENVIRONMENT"] ?? "Production";
                Response.Headers["X-Environment"] = env;

                // Security headers (defense in depth)
                Response.Headers["X-Content-Type-Options"] = "nosniff";
                Response.Headers["X-Frame-Options"] = "DENY";
                Response.Headers["X-XSS-Protection"] = "0"; // Rely on CSP/modern mitigations

                return Ok(new { message = "Action completed" });
            }
            catch (Exception ex)
            {
                _logger.LogError(ex,
                    "Error executing admin action {Action} for tenant {TenantId} by {AdminId}",
                    request.Action,
                    request.TenantId,
                    userId);

                // Graceful degradation: do not leak internals
                return StatusCode(500, "Internal server error.");
            }
        }
    }
}
```

**Defense in Depth Layers**:
1. **Authentication + Role Claims from Trusted Identity Provider**:
   - `[Authorize]` ensures only authenticated users.
   - Roles and `tenant_id` are taken from signed tokens/claims, not from the request body:
   ```csharp
   var role = User.FindFirstValue(ClaimTypes.Role);
   var tenantId = User.FindFirst("tenant_id")?.Value;
   ```

2. **Policy-Based Authorization and Tenant Isolation**:
   - Custom `ManageTenantUsersRequirement` and `ManageTenantUsersHandler` centralize complex logic.
   - Tenant boundary enforced both in the handler and in the controller:
   ```csharp
   if (!string.Equals(request.TenantId, userTenantId, StringComparison.Ordinal))
   {
       return Forbid();
   }
   ```

3. **Monitoring, Logging, and Secure Defaults**:
   - Detailed audit logs for each sensitive action:
   ```csharp
   _logger.LogInformation(
       "User {TargetUserId} disabled by {AdminId} in tenant {TenantId} at {Timestamp}",
       request.TargetUserId,
       userId,
       request.TenantId,
       DateTimeOffset.UtcNow);
   ```
   - Security headers applied on responses:
   ```csharp
   Response.Headers["X-Content-Type-Options"] = "nosniff";
   Response.Headers["X-Frame-Options"] = "DENY";
   ```

**Additional Protections**:
- **Environment-Specific Configuration**: Use `ASPNETCORE_ENVIRONMENT` to enable stricter settings in production (e.g., HTTPS redirection, secure cookies, stricter logging and monitoring).
- **Rate Limiting and Abuse Protection**: In production, add ASP.NET Core middleware or a gateway (e.g., Envoy, Azure APIM) to limit admin calls per user/IP and detect anomalous spikes.
- **Centralized Authorization Policies**: Register policies and handlers in `Program.cs`/`Startup` so all admin endpoints share consistent RBAC and tenant isolation rules, reducing the risk of one-off insecure endpoints.

Relying only on authentication or trusting client-supplied IDs is dangerous. You must enforce server-side, resource-based authorization on every access.

**VULNERABLE CODE**:

```csharp
using System;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;

namespace MyApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class OrdersController : ControllerBase
    {
        private readonly AppDbContext _db;

        public OrdersController(AppDbContext db)
        {
            _db = db;
        }

        // Vulnerable: Only checks that the user is authenticated
        [HttpGet("{orderId}")]
        public IActionResult GetOrder(Guid orderId)
        {
            if (!User.Identity?.IsAuthenticated ?? true)
            {
                return Unauthorized();
            }

            // No check that this order belongs to the current user
            var order = _db.Orders
                .AsNoTracking()
                .FirstOrDefault(o => o.Id == orderId);

            if (order == null)
            {
                return NotFound();
            }

            return Ok(order);
        }
    }

    public class AppDbContext : DbContext
    {
        public DbSet<Order> Orders { get; set; } = null!;
    }

    public class Order
    {
        public Guid Id { get; set; }
        public Guid CustomerId { get; set; }
        public string Item { get; set; } = string.Empty;
        public decimal Total { get; set; }
    }
}
```

**Attack Payload** (HTTP request):
```text
GET /api/orders/1a5ce5af-1e3b-4c9f-9f68-9a79f6d0b123 HTTP/1.1
Host: shop.example.com
Authorization: Bearer VALID_TOKEN_OF_OTHER_USER
```

This request simply guesses or enumerates another user's `orderId`.

**Why This Is Dangerous**:
- Any authenticated user can access any order by ID, leaking personal and financial data.
- Attackers can enumerate GUIDs/IDs or discover them via logs or side channels.
- There is no server-side enforcement of ownership or role-based rules per resource.

**SECURE VERSION**:

```csharp
using System;
using System.Security.Claims;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;

namespace MyApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class OrdersController : ControllerBase
    {
        private readonly AppDbContext _db;
        private readonly IAuthorizationService _authorizationService;

        public OrdersController(AppDbContext db, IAuthorizationService authorizationService)
        {
            _db = db;
            _authorizationService = authorizationService;
        }

        [HttpGet("{orderId}")]
        public async Task<IActionResult> GetOrder(Guid orderId)
        {
            if (!User.Identity?.IsAuthenticated ?? true)
            {
                return Unauthorized();
            }

            var order = await _db.Orders
                .AsNoTracking()
                .FirstOrDefaultAsync(o => o.Id == orderId);

            if (order == null)
            {
                return NotFound();
            }

            // Resource-based authorization
            var authResult = await _authorizationService.AuthorizeAsync(User, order, "OrderOwnerPolicy");

            if (!authResult.Succeeded)
            {
                // Log the attempt (simplified example)
                Console.Error.WriteLine($"[WARN] User {User.FindFirstValue(ClaimTypes.NameIdentifier)} " +
                                        $"attempted to access order {order.Id} without permission.");
                return Forbid();
            }

            return Ok(order);
        }
    }

    // Authorization requirement and handler
    public class OrderOwnerRequirement : IAuthorizationRequirement { }

    public class OrderOwnerHandler : AuthorizationHandler<OrderOwnerRequirement, Order>
    {
        protected override Task HandleRequirementAsync(
            AuthorizationHandlerContext context,
            OrderOwnerRequirement requirement,
            Order resource)
        {
            var userId = context.User.FindFirstValue(ClaimTypes.NameIdentifier);
            if (userId == null)
            {
                return Task.CompletedTask;
            }

            // Compare the order's CustomerId with the current user id
            if (Guid.TryParse(userId, out var parsedUserId) && resource.CustomerId == parsedUserId)
            {
                context.Succeed(requirement);
            }

            return Task.CompletedTask;
        }
    }

    public class AppDbContext : DbContext
    {
        public DbSet<Order> Orders { get; set; } = null!;
    }

    public class Order
    {
        public Guid Id { get; set; }
        public Guid CustomerId { get; set; }
        public string Item { get; set; } = string.Empty;
        public decimal Total { get; set; }
